/**
 * Analytics data models for the dashboard API.
 *
 * These types define the request/response contracts for all analytics endpoints.
 * The analytics service (to be implemented) will aggregate data from
 * OrderRepository and UserRepository into these shapes.
 */

// ---------------------------------------------------------------------------
// Query parameters
// ---------------------------------------------------------------------------

/**
 * Time granularity for time-series data.
 */
export type TimeGranularity = 'hour' | 'day' | 'week' | 'month';

/**
 * Supported metric types that can be queried individually.
 */
export type MetricType = 'orders' | 'revenue' | 'users' | 'average-order-value';

/**
 * Common query parameters shared across analytics endpoints.
 * All date ranges are inclusive on both ends.
 */
export interface AnalyticsQuery {
  /** Start of the date range (ISO 8601) */
  startDate: string;
  /** End of the date range (ISO 8601) */
  endDate: string;
  /** Optional user ID to scope analytics to a single user */
  userId?: string;
}

/**
 * Query parameters specific to the time-series endpoint.
 */
export interface TimeSeriesQuery extends AnalyticsQuery {
  /** Which metric to chart */
  metric: MetricType;
  /** Bucket size for aggregation (default: 'day') */
  granularity?: TimeGranularity;
}

// ---------------------------------------------------------------------------
// Response shapes
// ---------------------------------------------------------------------------

/**
 * A single data point in a time series.
 */
export interface TimeSeriesPoint {
  /** Bucket timestamp (start of the period, ISO 8601) */
  timestamp: string;
  /** Aggregated value for this period */
  value: number;
  /** Optional label (e.g. "Mon", "Week 12") */
  label?: string;
}

/**
 * Summary of a single metric with period-over-period comparison.
 */
export interface MetricSummary {
  /** Which metric this summarizes */
  type: MetricType;
  /** Human-readable label */
  label: string;
  /** Current-period value */
  value: number;
  /** Previous-period value (same duration, immediately preceding) */
  previousValue: number;
  /** Percentage change from previous period: ((value - previousValue) / previousValue) * 100 */
  changePercent: number;
  /** Direction of change */
  trend: 'up' | 'down' | 'flat';
}

/**
 * Breakdown of orders by status.
 */
export interface OrderStatusBreakdown {
  status: string;
  count: number;
  /** Percentage of total orders */
  percent: number;
}

/**
 * A product ranked by sales performance.
 */
export interface TopProduct {
  productId: string;
  name: string;
  totalQuantity: number;
  totalRevenue: number;
}

/**
 * Full dashboard response — returned by GET /api/analytics/dashboard.
 * Provides everything a dashboard UI needs in a single request.
 */
export interface DashboardData {
  /** High-level KPI cards */
  metrics: MetricSummary[];
  /** Order counts grouped by status */
  ordersByStatus: OrderStatusBreakdown[];
  /** Revenue over time (daily by default) */
  revenueTimeSeries: TimeSeriesPoint[];
  /** The date range these results cover */
  query: AnalyticsQuery;
  /** When this response was generated (ISO 8601) */
  generatedAt: string;
}

/**
 * Response for GET /api/analytics/metrics/:type
 */
export interface MetricDetailResponse {
  metric: MetricSummary;
  timeSeries: TimeSeriesPoint[];
  query: AnalyticsQuery;
  generatedAt: string;
}

/**
 * Response for GET /api/analytics/timeseries
 */
export interface TimeSeriesResponse {
  metric: MetricType;
  granularity: TimeGranularity;
  points: TimeSeriesPoint[];
  query: AnalyticsQuery;
  generatedAt: string;
}

/**
 * Response for GET /api/analytics/top-products
 */
export interface TopProductsResponse {
  products: TopProduct[];
  query: AnalyticsQuery;
  generatedAt: string;
}

/**
 * Framework-agnostic route handler types.
 *
 * These types decouple route logic from any HTTP framework (Express, Fastify, etc.).
 * A thin framework adapter translates incoming HTTP requests into RouteRequest
 * and serializes RouteResponse back to the client.
 *
 * This approach keeps all analytics logic testable without HTTP concerns.
 */

/**
 * Parsed route parameters (e.g. { type: 'revenue' } from /metrics/:type).
 */
export type RouteParams = Record<string, string>;

/**
 * Parsed query string parameters.
 */
export type QueryParams = Record<string, string | string[] | undefined>;

/**
 * A normalized incoming request, independent of HTTP framework.
 */
export interface RouteRequest<
  TParams extends RouteParams = RouteParams,
  TQuery extends QueryParams = QueryParams,
  TBody = unknown,
> {
  params: TParams;
  query: TQuery;
  body: TBody;
}

/**
 * A normalized outgoing response.
 */
export interface RouteResponse<TData = unknown> {
  status: number;
  data: TData;
}

/**
 * A route handler function.
 */
export type RouteHandler<
  TData = unknown,
  TParams extends RouteParams = RouteParams,
  TQuery extends QueryParams = QueryParams,
  TBody = unknown,
> = (req: RouteRequest<TParams, TQuery, TBody>) => Promise<RouteResponse<TData>>;

/**
 * HTTP methods supported by route definitions.
 */
export type HttpMethod = 'GET' | 'POST' | 'PUT' | 'DELETE' | 'PATCH';

/**
 * A route definition that can be registered with any HTTP framework adapter.
 */
export interface RouteDefinition<TData = unknown> {
  method: HttpMethod;
  path: string;
  handler: RouteHandler<TData>;
  description?: string;
}

/**
 * Analytics service — aggregates order and user data into dashboard metrics.
 *
 * Depends on:
 * - OrderRepository (data layer) for order data
 * - UserRepository (data layer) for user counts
 *
 * ## Implementation guide for downstream developers
 *
 * Each public method corresponds to one API endpoint. The methods currently
 * return placeholder data so the routes compile and return realistic shapes.
 * Replace each placeholder with real aggregation logic:
 *
 * 1. getDashboard  → query orders + users in the date range, compute KPIs,
 *                     bucket revenue into a daily time series, count statuses.
 * 2. getMetric     → compute a single KPI with period-over-period comparison.
 * 3. getTimeSeries → bucket the chosen metric by the requested granularity.
 * 4. getTopProducts→ aggregate OrderItem quantities and revenue, sort descending.
 *
 * Date filtering: parse AnalyticsQuery.startDate / endDate into Date objects
 * and filter repository results by createdAt. For period-over-period, compute
 * a "previous period" of equal duration immediately before startDate.
 */

import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type {
  AnalyticsQuery,
  DashboardData,
  MetricDetailResponse,
  MetricSummary,
  MetricType,
  TimeGranularity,
  TimeSeriesPoint,
  TimeSeriesQuery,
  TimeSeriesResponse,
  TopProductsResponse,
} from '../models/analytics.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Full dashboard summary — powers GET /api/analytics/dashboard.
   *
   * TODO: Replace placeholder with real aggregation:
   *   1. Query all orders in [startDate, endDate]
   *   2. Compute metrics: total orders, revenue, users, AOV
   *   3. Compute previous-period values for trend arrows
   *   4. Bucket revenue into daily TimeSeriesPoints
   *   5. Count orders by status
   */
  async getDashboard(query: AnalyticsQuery): Promise<DashboardData> {
    this.logger.info(`Generating dashboard for ${query.startDate} to ${query.endDate}`);

    const now = new Date().toISOString();

    return {
      metrics: [
        this.placeholderMetric('orders', 'Total Orders', 0),
        this.placeholderMetric('revenue', 'Total Revenue', 0),
        this.placeholderMetric('users', 'New Users', 0),
        this.placeholderMetric('average-order-value', 'Avg Order Value', 0),
      ],
      ordersByStatus: [
        { status: 'pending', count: 0, percent: 0 },
        { status: 'confirmed', count: 0, percent: 0 },
        { status: 'shipped', count: 0, percent: 0 },
        { status: 'delivered', count: 0, percent: 0 },
        { status: 'cancelled', count: 0, percent: 0 },
      ],
      revenueTimeSeries: [],
      query,
      generatedAt: now,
    };
  }

  /**
   * Single metric detail — powers GET /api/analytics/metrics/:type.
   *
   * TODO: Replace placeholder with real aggregation for the given metric type.
   */
  async getMetric(type: MetricType, query: AnalyticsQuery): Promise<MetricDetailResponse> {
    this.logger.info(`Generating metric detail for ${type}`);

    return {
      metric: this.placeholderMetric(type, this.metricLabel(type), 0),
      timeSeries: [],
      query,
      generatedAt: new Date().toISOString(),
    };
  }

  /**
   * Time series data — powers GET /api/analytics/timeseries.
   *
   * TODO: Replace placeholder with real bucketed aggregation.
   *   - Parse granularity to determine bucket boundaries
   *   - Aggregate the chosen metric into each bucket
   */
  async getTimeSeries(query: TimeSeriesQuery): Promise<TimeSeriesResponse> {
    const granularity: TimeGranularity = query.granularity ?? 'day';
    this.logger.info(`Generating time series for ${query.metric} by ${granularity}`);

    return {
      metric: query.metric,
      granularity,
      points: [],
      query,
      generatedAt: new Date().toISOString(),
    };
  }

  /**
   * Top products by revenue — powers GET /api/analytics/top-products.
   *
   * TODO: Replace placeholder:
   *   1. Query all orders in date range
   *   2. Flatten order items
   *   3. Group by productId, sum quantity and revenue
   *   4. Sort by totalRevenue descending, take top N (default 10)
   */
  async getTopProducts(query: AnalyticsQuery, limit: number = 10): Promise<TopProductsResponse> {
    this.logger.info(`Generating top ${limit} products`);

    return {
      products: [],
      query,
      generatedAt: new Date().toISOString(),
    };
  }

  // ---------------------------------------------------------------------------
  // Helpers (keep these — they're useful for the real implementation too)
  // ---------------------------------------------------------------------------

  private placeholderMetric(type: MetricType, label: string, value: number): MetricSummary {
    return {
      type,
      label,
      value,
      previousValue: 0,
      changePercent: 0,
      trend: 'flat',
    };
  }

  private metricLabel(type: MetricType): string {
    const labels: Record<MetricType, string> = {
      orders: 'Total Orders',
      revenue: 'Total Revenue',
      users: 'New Users',
      'average-order-value': 'Avg Order Value',
    };
    return labels[type];
  }
}

/**
 * Analytics route definitions.
 *
 * Each route maps an HTTP endpoint to an AnalyticsService method.
 * Handlers parse/validate query parameters, call the service, and
 * return a typed RouteResponse.
 *
 * These are framework-agnostic — register them with any HTTP adapter.
 *
 * Routes:
 *   GET /api/analytics/dashboard      → full dashboard summary
 *   GET /api/analytics/metrics/:type  → single metric with time series
 *   GET /api/analytics/timeseries     → raw time-series data
 *   GET /api/analytics/top-products   → top products by revenue
 */

import type { AnalyticsService } from '../services/analytics.service.js';
import type { MetricType, TimeGranularity } from '../models/analytics.js';
import type { RouteDefinition, RouteHandler } from './types.js';

const VALID_METRIC_TYPES: MetricType[] = ['orders', 'revenue', 'users', 'average-order-value'];
const VALID_GRANULARITIES: TimeGranularity[] = ['hour', 'day', 'week', 'month'];

/**
 * Parse and validate the common date-range query parameters.
 * Returns default last-30-days range if not provided.
 */
function parseDateRange(query: Record<string, string | string[] | undefined>): {
  startDate: string;
  endDate: string;
  userId?: string;
} {
  const now = new Date();
  const thirtyDaysAgo = new Date(now);
  thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

  return {
    startDate: (typeof query.startDate === 'string' ? query.startDate : null) ?? thirtyDaysAgo.toISOString(),
    endDate: (typeof query.endDate === 'string' ? query.endDate : null) ?? now.toISOString(),
    userId: typeof query.userId === 'string' ? query.userId : undefined,
  };
}

/**
 * Create all analytics route definitions bound to the given service instance.
 */
export function createAnalyticsRoutes(service: AnalyticsService): RouteDefinition[] {
  // GET /api/analytics/dashboard
  const getDashboard: RouteHandler = async (req) => {
    const query = parseDateRange(req.query);
    const data = await service.getDashboard(query);
    return { status: 200, data };
  };

  // GET /api/analytics/metrics/:type
  const getMetricByType: RouteHandler = async (req) => {
    const type = req.params.type as MetricType;

    if (!VALID_METRIC_TYPES.includes(type)) {
      return {
        status: 400,
        data: {
          error: `Invalid metric type: "${type}". Must be one of: ${VALID_METRIC_TYPES.join(', ')}`,
        },
      };
    }

    const query = parseDateRange(req.query);
    const data = await service.getMetric(type, query);
    return { status: 200, data };
  };

  // GET /api/analytics/timeseries
  const getTimeSeries: RouteHandler = async (req) => {
    const metric = req.query.metric as MetricType | undefined;
    if (!metric || !VALID_METRIC_TYPES.includes(metric)) {
      return {
        status: 400,
        data: {
          error: `Query parameter "metric" is required and must be one of: ${VALID_METRIC_TYPES.join(', ')}`,
        },
      };
    }

    const granularity = (req.query.granularity as TimeGranularity | undefined) ?? 'day';
    if (!VALID_GRANULARITIES.includes(granularity)) {
      return {
        status: 400,
        data: {
          error: `Invalid granularity: "${granularity}". Must be one of: ${VALID_GRANULARITIES.join(', ')}`,
        },
      };
    }

    const dateRange = parseDateRange(req.query);
    const data = await service.getTimeSeries({
      ...dateRange,
      metric,
      granularity,
    });
    return { status: 200, data };
  };

  // GET /api/analytics/top-products
  const getTopProducts: RouteHandler = async (req) => {
    const query = parseDateRange(req.query);
    const limitParam = typeof req.query.limit === 'string' ? parseInt(req.query.limit, 10) : 10;
    const limit = Number.isFinite(limitParam) && limitParam > 0 ? limitParam : 10;
    const data = await service.getTopProducts(query, limit);
    return { status: 200, data };
  };

  return [
    {
      method: 'GET',
      path: '/api/analytics/dashboard',
      handler: getDashboard,
      description: 'Full dashboard summary with KPIs, status breakdown, and revenue chart',
    },
    {
      method: 'GET',
      path: '/api/analytics/metrics/:type',
      handler: getMetricByType,
      description: 'Single metric detail with period-over-period comparison and time series',
    },
    {
      method: 'GET',
      path: '/api/analytics/timeseries',
